package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.WerkbonusLuik;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.core.SqlParameterValue;
import org.springframework.transaction.annotation.Transactional;

import javax.sql.DataSource;
import java.sql.Types;

@Transactional
public class StandaardWerkBonusFiscaalJaarService implements WerkBonusFiscaalJaarService {

    private static final String GET_KEY_OTHER_SQL = "select sum(rb.bedrag) from rekenhoofd rh" + " join opdracht_master om on om.id=rh.opdrachtid"
            + " join rekenlijn rl on rl.rekenhoofdid=rh.id " + " join rekenbedrag rb on rl.id=rb.rekenlijnid"
            + " where bedragtypectid=? and om.persoonId=? and fiscaal_jaar=? and rh.begindatum!=?" +
            " and rh.hoedanigheidctid =?";

    @Autowired
    private DataSource dataSource;

    @Override
    public Money getVerminderingBvWerkbonusFiscaalJaarOtherMonths(Admin admin, Persoon persoon, Integer fiscaalJaar, LocalDate beginDatum, WerkbonusLuik luik) {
        return executeQuery(persoon, fiscaalJaar, beginDatum, luik.getVerminderingKey().toEnumType());
    }

    @Override
    public Money getWerkbonusFiscaalJaarOtherMonths(Admin admin, Persoon persoon, Integer fiscaalJaar, LocalDate beginDatum, WerkbonusLuik luik) {
        return executeQuery(persoon, fiscaalJaar, beginDatum, luik.getBedragKey().toEnumType());
    }

    private Money executeQuery(Persoon persoon, Integer fiscaalJaar, LocalDate beginDatum, RekenBedragType rekenBedragType) {
        JdbcTemplate jdbc = new JdbcTemplate(dataSource);
        Object[] args = new Object[5];
        args[0] = new SqlParameterValue(Types.VARCHAR, rekenBedragType.getId());
        args[1] = new SqlParameterValue(Types.INTEGER, persoon.getId());
        args[2] = new SqlParameterValue(Types.INTEGER, fiscaalJaar);
        args[3] = new SqlParameterValue(Types.DATE, new java.sql.Date(beginDatum.toDate().getTime()));
        args[4] = new SqlParameterValue(Types.VARCHAR, Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN.getId());
        String resultaat = jdbc.queryForObject(GET_KEY_OTHER_SQL, args, String.class);

        Money result = Money.ZERO;
        if (resultaat != null) {
            result = new Money(resultaat);
        }
        return result;
    }
}
